// Formspree — direct form submission
const FORMSPREE_URL = "https://formspree.io/f/mlgpvejw";

function sendEmail(params) {
  const body = Object.entries(params)
    .map(([k,v]) => encodeURIComponent(k) + "=" + encodeURIComponent(v || "—"))
    .join("&");
  return fetch(FORMSPREE_URL, {
    method: "POST",
    headers: {
      "Content-Type": "application/x-www-form-urlencoded",
      "Accept": "application/json"
    },
    body: body
  }).then(function(res) {
    if (res.ok) return res;
    return res.json().then(function(data) {
      throw new Error(data.error || "Submission failed");
    });
  });
}

// Articles data

const articles = [
  {id:"ins",tag:"INSURANCE",code:"WP-001",title:"Why Insurance Firms Face the Highest AI Act Exposure in 2026",excerpt:"Credit scoring and underwriting AI are classified as high-risk systems. Here is exactly what Article 14 requires before August 2.",date:"2026-02-18",readTime:"7 min",body:`<p>The EU AI Act does not treat all industries equally. For insurance firms, the classification of AI-assisted underwriting and credit scoring as <strong>high-risk systems</strong> under Annex III creates a compliance burden that most firms are not yet ready to meet.</p><h2>What Article 14 Actually Requires</h2><p>Article 14 mandates Human Oversight — but not in the way most compliance teams interpret it. It is not enough to have a human "review" AI outputs. The regulation requires firms to demonstrate that humans can <strong>intervene, override, and document</strong> every consequential decision made by the AI system.</p><p>This creates a significant audit trail requirement. Every decision node must be logged, timestamped, and attributable to a named human authorised to override the system.</p><h2>The Double Pressure: Regulators and Carriers</h2><p>Insurance firms face a unique double bind. Regulators are coming for AI compliance documentation. But simultaneously, cyber insurance carriers are conditioning coverage on documented evidence of AI risk assessments. Firms that cannot produce an audit trail may find themselves both non-compliant with the AI Act and uninsurable for AI-related liabilities.</p><h2>The August 2 Cliff</h2><p>The enforcement deadline is not a soft target. Firms operating high-risk AI systems without documented compliance frameworks face fines of up to €30 million or 6% of global annual turnover. For mid-sized insurance firms, this is an existential financial exposure.</p><p>Axiom Forensics has designed its <strong>Emergency Protocol</strong> specifically to produce the documentation trail required for Article 14 compliance — in 48 hours.</p>`},
  {id:"art50",tag:"LEGAL TECH",code:"WP-002",title:"Article 50 Transparency: What Law Firms Must Disclose About AI-Generated Documents",excerpt:"Courts are already sanctioning firms for undisclosed AI use. Article 50 codifies what disclosure looks like under the AI Act.",date:"2026-01-30",readTime:"5 min",body:`<p>Courts in the United States and United Kingdom have already issued sanctions against law firms for submitting AI-generated content without disclosure. The EU AI Act's Article 50 now formalises this as a legal obligation — not just an ethical one.</p><h2>What Article 50 Requires</h2><p>Any AI system that interacts with humans or generates content must clearly disclose its AI nature. For law firms, this means client-facing AI tools — including document drafting assistants, contract review platforms, and legal research engines — must carry auditable disclosure mechanisms.</p><p>The obligation extends beyond client communications. Internal AI-generated documents that inform legal advice may also require disclosure under the regulation's broader transparency mandate.</p><h2>The Logic Gap in Current Legal AI Tools</h2><p>Most legal AI platforms (Clio, Harvey, Copilot) do not currently generate the compliance documentation that Article 50 requires. They produce outputs. They do not produce <strong>audit-ready transparency reports</strong> that satisfy regulatory review.</p><p>This is the gap Axiom Forensics audits — systematically, and on a 48-hour turnaround.</p>`},
  {id:"cop",tag:"FORENSICS",code:"WP-003",title:"The Microsoft Copilot Liability Gap: What Your Firm's IT Team Isn't Telling You",excerpt:"Copilot accesses your firm's entire document history. Here is the Article 14 exposure most compliance teams are missing.",date:"2026-01-12",readTime:"6 min",body:`<p>Microsoft Copilot is now deployed in over 60% of mid-sized professional services firms in Western Europe. Most IT departments approved the deployment based on Microsoft's general data processing agreements — not on an analysis of Article 14 compliance obligations specific to the firm's AI use case.</p><h2>The Access Problem</h2><p>Copilot's architecture grants it access to the firm's entire Microsoft 365 ecosystem — emails, documents, Teams conversations, SharePoint files. Under Article 14, the firm — not Microsoft — is responsible for ensuring human oversight of any consequential decisions made using Copilot's outputs. The vendor agreement does not transfer this liability.</p><h2>What a Forensic Audit Reveals</h2><p>An Axiom Forensics diagnostic of a Copilot deployment typically identifies three categories of exposure: access scope violations, output traceability gaps, and missing override documentation. Each category carries independent regulatory exposure under the AI Act.</p>`},
  {id:"nist",tag:"COMPLIANCE",code:"WP-004",title:"NIST AI RMF Alignment for Insurance Underwriting Systems: A Practical Checklist",excerpt:"The NIST AI Risk Management Framework is becoming the baseline for regulatory defense. Here is what alignment actually requires.",date:"2025-12-20",readTime:"8 min",body:`<p>The National Institute of Standards and Technology AI Risk Management Framework (NIST AI RMF) has become the de facto baseline for demonstrating AI governance maturity to regulators, auditors, and enterprise clients.</p><h2>The Four Core Functions</h2><p>The NIST AI RMF is organised around four functions: Govern, Map, Measure, and Manage. Insurance firms typically have partial implementations of Govern and Map — but few have systematically addressed Measure and Manage for their underwriting AI systems.</p><p>The Measure function requires ongoing performance monitoring of AI outputs against defined risk thresholds. The Manage function requires documented incident response protocols for AI system failures. Both are required for EU AI Act compliance.</p><h2>The Audit as Evidence</h2><p>A documented Axiom Forensics audit constitutes evidence of Measure and Manage function implementation — directly mappable to both NIST AI RMF and EU AI Act Article 14 requirements. One engagement. Dual compliance coverage.</p>`},

  {id:"digital-omnibus",tag:"REGULATION",code:"WP-005",title:"EU AI Act Digital Omnibus Delay: What It Actually Means for Law Firms and Insurance Companies in 2026",excerpt:"The proposed Digital Omnibus would delay some AI Act obligations to 2027. But it is not law yet and most firms are still fully in scope for August 2. Here is exactly what changed and what did not.",date:"2026-03-18",readTime:"9 min",body:`<p>In early 2026, the European Commission proposed the Digital Omnibus — a package of regulatory amendments that includes a proposed delay to certain EU AI Act obligations. Law firms and insurance companies across the UK and EU have been asking the same question ever since: does this mean we have more time?</p><p>The short answer is no. The longer answer is more important to understand.</p><h2>What the Digital Omnibus Actually Proposes</h2><p>The Digital Omnibus is a proposed amendment package — not enacted law. It has not passed the European Parliament. It has not been signed into force. As of March 2026, it remains a Commission proposal under active legislative debate.</p><p>The proposal suggests delaying certain obligations under the AI Act's general-purpose AI provisions and some Annex III high-risk system requirements from August 2026 to December 2027. But this delay applies only to a specific subset of obligations — and critically, it does not apply to the core Article 14 human oversight requirements or the Article 50 transparency obligations that affect most law firms and insurance carriers currently using AI systems.</p><h2>What Is Still Enforced on August 2, 2026</h2><p>The August 2, 2026 enforcement date remains legally binding for all firms operating high-risk AI systems as classified under Annex III. This includes AI systems used for credit scoring, insurance underwriting decisions, and legal document analysis that informs consequential client advice.</p><p><strong>Article 14 — Human Oversight</strong> is not affected by the Digital Omnibus proposal. Firms must still demonstrate documented human oversight of every consequential AI decision before August 2.</p><p><strong>Article 50 — Transparency</strong> is not affected by the Digital Omnibus proposal. Client-facing AI tools must still carry auditable disclosure mechanisms before August 2.</p><p><strong>Annex III classification</strong> is not affected. If your underwriting or credit scoring AI was classified as high-risk before the proposal, it remains high-risk under the current law.</p><h2>Why This Matters for Your Compliance Timeline</h2><p>The Digital Omnibus proposal has created a dangerous false comfort in the market. Compliance teams have read headlines about a delay and assumed their August deadline has moved. It has not. The firms that act on this assumption and postpone their compliance documentation will face the full force of enforcement on August 2 with nothing to show regulators.</p><p>There is a second risk that is less discussed. Even if the Digital Omnibus passes in its current form before August 2 — which is unlikely given the legislative timeline — the delay it proposes is narrow. Firms that have already deployed high-risk AI systems without any governance documentation will not benefit from a prospective delay. Regulators will ask for the historical deployment record.</p><h2>The Practical Position for UK Firms</h2><p>UK firms face an additional layer of complexity. Post-Brexit, the UK is developing its own AI regulatory framework independently of the EU AI Act. However, any UK firm with EU clients, EU data subjects, or EU operations is still subject to the EU AI Act's extraterritorial provisions. The Digital Omnibus does not change this extraterritorial reach.</p><p>The practical position for any UK insurance firm or law firm with EU exposure is straightforward: treat the August 2 deadline as fixed, complete your compliance documentation now, and treat any future delay as a bonus — not a plan.</p><h2>What Axiom Forensics Recommends</h2><p>We have reviewed every public version of the Digital Omnibus proposal and its progress through the legislative process. Our position is unambiguous. No firm should delay compliance documentation on the basis of an unratified proposal. The cost of being wrong — up to €35 million or 7% of global turnover — is not a risk any responsible compliance officer should accept on the basis of a legislative proposal that may not pass, may not pass in its current form, and may not apply to your specific AI systems even if it does.</p><p>If you have questions about whether your firm's specific AI systems are affected by the Digital Omnibus proposal, an Axiom Forensics Emergency Protocol assessment will give you a definitive answer in 48 hours.</p>`},

  {id:"harvey-ai-article50",tag:"LEGAL TECH",code:"WP-006",title:"Harvey AI and Article 50: The Compliance Gap Every UK Law Firm Needs to Know About",excerpt:"Harvey AI is now deployed in hundreds of UK law firms. Article 50 of the EU AI Act creates specific disclosure obligations for every client-facing use. Most firms are not meeting them.",date:"2026-03-10",readTime:"7 min",body:`<p>Harvey AI has become the dominant AI platform in UK legal practice. Backed by major investment and integrated into the workflows of hundreds of law firms across the UK and EU, it is used daily for document drafting, contract review, legal research, and client advice preparation. It is also, for most of the firms using it, an undocumented Article 50 liability.</p><h2>What Article 50 Requires</h2><p>Article 50 of the EU AI Act imposes transparency obligations on any AI system that interacts with natural persons or generates content used in client-facing contexts. The obligation is not vague. It requires that the AI nature of the system be clearly disclosed, that disclosure be auditable, and that firms maintain records demonstrating compliance with the transparency requirement.</p><p>For a law firm using Harvey AI to draft client advice, review contracts, or generate legal research summaries, Article 50 applies to every client interaction where that output is used. The firm — not Harvey — bears the compliance obligation.</p><h2>What Harvey AI Does and Does Not Provide</h2><p>Harvey AI is an exceptional legal tool. It produces high-quality outputs, integrates with existing firm workflows, and is trusted by some of the most sophisticated legal practices in the world. What it does not currently provide is the Article 50 compliance documentation that EU and UK-EU firms require.</p><p>Harvey generates legal outputs. It does not generate audit-ready transparency reports. It does not produce the disclosure records that a regulator will request in a compliance inquiry. It does not timestamp and archive evidence that your firm met the Article 50 obligation on each client matter where AI was used. That documentation gap is the firm's responsibility — and it is where Axiom Forensics operates.</p><h2>The Specific Documentation Gap</h2><p>An Axiom Forensics assessment of a Harvey AI deployment typically identifies three specific documentation failures. First, the absence of a firm-wide Harvey AI disclosure protocol for client communications. Second, the absence of matter-level records showing when Harvey outputs were used and what disclosure was made to the client. Third, the absence of a system-level transparency report mapping Harvey's use to the Article 50 obligation.</p><p>Each of these failures is independently actionable by regulators. Together they represent a systemic Article 50 non-compliance that exposes the firm to penalties regardless of how carefully Harvey is actually being used.</p><h2>What Remediation Looks Like</h2><p>The good news is that Article 50 compliance for a Harvey AI deployment is achievable quickly. An Axiom Forensics Emergency Protocol produces the three core documents required: a Harvey AI system transparency report, a matter-level disclosure protocol, and an Article 50 compliance record template that integrates into the firm's existing file management system.</p><p>Firms that complete this remediation before August 2, 2026 are fully protected. Firms that do not are exposed to regulatory action on every client matter where Harvey has been used without documented disclosure — potentially extending back to the date of Harvey's deployment at the firm.</p><p>If your firm is using Harvey AI and you do not have Article 50 compliance documentation in place, an Axiom Forensics assessment is the fastest path to protection. The Emergency Protocol is delivered in 48 hours.</p>`},

  {id:"zurich-aviva-ai-compliance",tag:"INSURANCE",code:"WP-007",title:"Why Zurich and Aviva Are Now Demanding AI Compliance Documentation From Counterparties",excerpt:"Tier 1 insurance carriers are making AI governance documentation a condition of coverage and commercial relationships. Here is what they are asking for and why.",date:"2026-03-05",readTime:"6 min",body:`<p>A significant shift is underway in the UK and EU insurance market. Tier 1 carriers including major composite insurers are beginning to require AI compliance documentation from the firms they work with — as a condition of both insurance coverage and commercial relationships. This is not a future development. It is happening now, in contract negotiations and renewal discussions across the market.</p><h2>Why Carriers Are Moving on AI Governance</h2><p>The logic is straightforward. Carriers face their own EU AI Act obligations for their underwriting AI systems. A carrier that underwrites a law firm or financial services firm that subsequently faces an AI Act enforcement action has underwritten a risk that was not disclosed, not assessed, and not priced. The market is correcting for this.</p><p>The correction takes two forms. Some carriers are adding AI governance warranties to their professional indemnity and cyber liability policy conditions — requiring policyholders to certify that their AI systems are compliant with applicable regulation. Others are conducting AI governance due diligence as part of the renewal process, requesting documentation of AI risk assessments and compliance frameworks before binding coverage.</p><h2>What Documentation Carriers Are Requesting</h2><p>Based on current market intelligence, the documentation requests from carriers cluster around three areas. First, evidence of AI system inventory — a documented list of all AI tools in use, their functions, and their risk classification under the EU AI Act. Second, evidence of human oversight protocols — specifically the Article 14 documentation showing how consequential AI decisions are reviewed and overridden by authorised humans. Third, evidence of transparency compliance — the Article 50 disclosure records showing how clients and counterparties are informed of AI use.</p><p>Firms that cannot produce this documentation at renewal are facing two outcomes. Either their coverage conditions are amended to exclude AI-related liabilities, or their premiums are adjusted to reflect the unquantified AI governance risk.</p><h2>The Commercial Relationship Dimension</h2><p>Beyond insurance, AI governance documentation is beginning to appear in commercial due diligence for law firm panel appointments, financial services outsourcing arrangements, and insurance distribution agreements. A firm pitching for panel counsel status at a major insurer is increasingly likely to be asked about its AI governance framework as part of the pitch evaluation.</p><p>This creates a commercial opportunity for firms that have completed their compliance documentation. An Axiom Forensics audit report is not just a regulatory defence document. It is a competitive differentiator in pitch situations where AI governance is on the evaluation criteria.</p><h2>The Timeline Pressure</h2><p>The carrier-driven pressure and the regulatory enforcement deadline are converging on the same date. August 2, 2026 is when EU AI Act enforcement begins. It is also, for many firms, when their annual professional indemnity and cyber liability policies renew. Firms that arrive at renewal without AI governance documentation face simultaneous regulatory exposure and insurance market pressure.</p><p>An Axiom Forensics Emergency Protocol produces the documentation package that satisfies both pressures — regulatory compliance documentation and the carrier due diligence package — in a single 48-hour engagement.</p>`},

  {id:"harvey-ai-article50-law-firm",tag:"LEGAL TECH",code:"WP-008",title:"Harvey AI Is In Your Firm. Here Is What Your Compliance Team Has Not Done Yet.",excerpt:"Hundreds of UK and Irish law firms are using Harvey AI daily. Almost none have the Article 50 documentation to prove it. Here is what that gap actually looks like.",date:"2025-11-04",readTime:"7 min",body:`<p>I want to start with something that most compliance consultants will not say directly. The problem with Harvey AI at most law firms is not the tool. Harvey is exceptional. The problem is the assumption that deploying a good tool means you are compliant with the obligations that come with using it.</p><p>Article 50 of the EU AI Act does not care how good your AI tool is. It requires you to prove you disclosed its use, to whom, when, and in what context. Per matter. Not as a blanket policy. Not as a footnote in your engagement letter. Per matter, with an auditable record that survives regulatory scrutiny.</p><h2>What I Find When I Walk Into a Harvey AI Deployment</h2><p>I have reviewed Harvey deployments across multiple firms. The pattern is almost identical every time. The firm has a Harvey usage policy. The policy says something like "associates must disclose AI use to supervisors." Nobody has built the disclosure record that connects Harvey's output on matter 4,471 to a named human reviewer who verified that output before it went to the client.</p><p>That connection is what Article 50 requires. Not the policy. The record.</p><p>When I run FM1 against a Harvey deployment, I am looking for exactly that linkage. Decision log to review log, connected by a shared identifier. In almost every first audit I run, that linkage does not exist. Harvey produced the output. A lawyer used it. Nobody recorded the disclosure chain in a form that a regulator can audit.</p><h2>Why This Is Not Harvey's Problem to Solve</h2><p>I hear this frequently. "Shouldn't Harvey be providing the compliance documentation?" The answer is no, and understanding why matters.</p><p>Harvey is a provider under the AI Act. Your firm is a deployer. The compliance obligations for deployers are separate from those of providers. Harvey must meet its own obligations. Your firm must meet yours. The fact that Harvey does not generate Article 50 compliance records does not reduce your firm's obligation to maintain them. It means your firm must build that documentation layer independently.</p><p>This is not a gap Harvey will close for you. It is a gap Axiom Forensics closes in 48 hours.</p><h2>The Retroactive Liability Problem</h2><p>Here is what concerns me most about the Harvey situation at UK and Irish law firms. The Article 50 obligation is not prospective only. Regulators can ask for disclosure records going back to the date of deployment. If your firm deployed Harvey in 2024 and you have no Article 50 compliance records from that point forward, you are non-compliant retroactively.</p><p>Every client matter where Harvey was used without documented disclosure is potential exposure. For a firm with high Harvey usage, that is a significant number of matters.</p><p>The Emergency Protocol produces a remediation package that addresses both the prospective obligation and the historical gap. If you are using Harvey AI and you do not have Article 50 records in place, the time to fix this is now, not August 1st.</p>`},

  {id:"copilot-article14-gap",tag:"LEGAL TECH",code:"WP-009",title:"Microsoft Copilot Is Accessing Everything. Your Article 14 Documentation Covers Nothing.",excerpt:"Copilot has been approved by IT. It has not been approved for Article 14 compliance. These are completely different things.",date:"2025-11-18",readTime:"6 min",body:`<p>When Microsoft Copilot arrived in most professional services firms, it came through the IT department. The IT team reviewed Microsoft's data processing agreement, confirmed it met GDPR requirements, and approved deployment. That approval covered data privacy. It covered cybersecurity. It did not cover Article 14 of the EU AI Act, because at the time most IT departments were not thinking about Article 14.</p><p>That is the gap I walk into on almost every Copilot engagement.</p><h2>What IT Approved and What It Did Not</h2><p>The Microsoft data processing agreement for Copilot is comprehensive on data protection. It covers where data is stored, how it is processed, and what Microsoft's obligations are under GDPR. It says nothing about your firm's Article 14 obligations, because those obligations belong to your firm as the deployer, not to Microsoft as the provider.</p><p>Article 14 requires your firm to demonstrate that a named human with appropriate authority reviewed and could have overridden any consequential AI-assisted decision. Copilot does not generate that record. Microsoft's DPA does not require Microsoft to generate that record. Your IT team did not build that record into the deployment. And now you have a Copilot deployment that is fully GDPR compliant and potentially Article 14 non-compliant.</p><h2>The Scope Problem</h2><p>Copilot's architecture makes this particularly complex. It has access to your firm's entire Microsoft 365 environment. Every email, document, Teams conversation, and SharePoint file. The range of consequential decisions that Copilot's outputs could influence is enormous. A Copilot-drafted email that influences a client's investment decision. A Copilot-summarised contract review that informs legal advice. A Copilot-generated meeting summary that shapes a board resolution.</p><p>Each of those use cases potentially triggers Article 14. And for each of them, your firm needs a documented oversight chain.</p><h2>What Remediation Actually Requires</h2><p>I am going to be direct about this because I think a lot of firms are underestimating what Article 14 compliance for a Copilot deployment actually requires. It is not a policy document. It is not a training session. It is a systematic documentation framework that creates a traceable record of human oversight for every consequential Copilot-assisted output.</p><p>That framework requires three things. Named human reviewers with documented authority. A log that connects Copilot outputs to those reviewers by a shared identifier. And evidence that those reviewers actively engaged with the output, not just approved it passively.</p><p>If your Copilot deployment does not have all three, you have an Article 14 gap. The Axiom Forensics Emergency Protocol builds that framework and produces the documentation in 48 hours. That is what compliance actually looks like.</p>`},

  {id:"clio-duo-article50-compliance",tag:"LEGAL TECH",code:"WP-010",title:"Clio Duo and Article 50: What the Platform Does Not Tell You About Your Compliance Obligation",excerpt:"Clio Duo is excellent at managing legal work. It does not manage your Article 50 compliance obligation. Here is the difference and why it matters before August 2.",date:"2025-12-03",readTime:"5 min",body:`<p>Clio has built something genuinely useful with Clio Duo. It integrates AI into the daily workflow of legal practice in a way that feels natural and adds real value. I use this as context because what I am about to say is not a criticism of the product. It is a clarification of something Clio Duo does not do, that firms are assuming it does.</p><p>Clio Duo does not generate Article 50 compliance documentation.</p><h2>What Article 50 Actually Requires</h2><p>Article 50 of the EU AI Act requires that your firm maintain auditable records demonstrating that clients were informed of AI use in their matter, when that disclosure was made, what was disclosed, and how the disclosure was documented. Per matter. Not as a general terms of engagement clause. Per matter, with a record that connects the specific AI use to the specific disclosure to the specific client.</p><p>Clio Duo produces AI-assisted outputs. It does not produce those disclosure records. The obligation to create and maintain them belongs to the firm, not to Clio.</p><h2>The Engagement Letter Problem</h2><p>The most common response I hear from firms using Clio Duo is "we added an AI clause to our engagement letters." I understand why this feels like compliance. It is not. A clause in an engagement letter is a contractual term. It is not an auditable disclosure record. It does not demonstrate per-matter compliance. It does not show that the specific AI use on a specific matter was disclosed in the way Article 50 requires.</p><p>Regulators are not going to review your engagement letter template. They are going to ask for the disclosure record for a specific matter. If that record does not exist as a documented artifact, the engagement letter clause does not save you.</p><h2>Building the Missing Layer</h2><p>The good news is that building this layer on top of Clio Duo is straightforward once you know what it requires. An Axiom Forensics assessment produces a Clio Duo specific Article 50 compliance framework. A disclosure record template that integrates with Clio's matter management. A protocol for creating per-matter compliance records. And the documentation that demonstrates to regulators that your disclosure obligation is being met systematically, not ad hoc. That is what the Emergency Protocol delivers. In 48 hours.</p>`},

  {id:"sra-ai-law-firms-2026",tag:"LEGAL TECH",code:"WP-011",title:"The SRA Has Not Forgotten About AI. Here Is What Solicitors Need to Have Ready.",excerpt:"The Solicitors Regulation Authority has been watching AI adoption across the profession. What it expects before August 2 is more specific than most firms realise.",date:"2025-12-15",readTime:"6 min",body:`<p>I want to be careful here because the SRA has not yet issued a definitive AI compliance framework with the same specificity as the EU AI Act itself. But careful reading of SRA communications over the last eighteen months, combined with the extraterritorial reach of the EU AI Act for UK firms with EU clients, creates a picture that every solicitor using AI needs to understand.</p><h2>What the SRA Has Said</h2><p>The SRA has been consistent on one point. Solicitors remain personally responsible for work product regardless of how it was generated. AI-generated content that goes to a client, informs advice, or appears in a court submission carries the same professional responsibility as anything written by the solicitor personally. The SRA has also been clear that it expects firms to have governance frameworks for AI use, not just policies.</p><p>The distinction between a policy and a governance framework is important. A policy says what the firm intends to do. A governance framework demonstrates what the firm actually does, with records to prove it. The SRA is moving toward expecting the latter.</p><h2>The EU AI Act Overlap for UK Firms</h2><p>UK firms are not directly subject to the EU AI Act as a matter of UK law. But any UK firm with EU clients, EU data subjects, or EU operations falls within the Act's extraterritorial scope. For most mid-sized UK law firms, that means the EU AI Act applies to a significant portion of their practice, even post-Brexit.</p><p>This creates a dual compliance pressure. SRA professional standards on one side. EU AI Act documentary requirements on the other. The overlap is significant and the documentation that satisfies one tends to satisfy both.</p><h2>What I Recommend for UK Solicitors</h2><p>Build the documentation framework now. Not because the SRA has issued a specific enforcement notice, but because the direction of travel is unambiguous. Every SRA communication on AI points toward documentary accountability. Every EU AI Act provision points toward the same thing. Firms that build this framework before August 2 are positioned correctly for both regimes. Firms that wait are building it under pressure, after the fact, which is always more expensive and less defensible. The Axiom Forensics Emergency Protocol gives UK law firms the documentary foundation that works for both the SRA governance expectation and the EU AI Act compliance requirement.</p>`},

  {id:"legal-ai-client-privilege-article50",tag:"LEGAL TECH",code:"WP-012",title:"Legal AI, Client Privilege, and Article 50: The Intersection Nobody Is Talking About",excerpt:"Article 50 disclosure requirements and legal professional privilege create a tension in legal AI compliance that most firms have not thought through. Here is what it actually looks like.",date:"2026-01-08",readTime:"7 min",body:`<p>I want to raise something that comes up in almost every law firm engagement I run, and that I have not seen addressed clearly anywhere in the compliance literature. The intersection of Article 50 transparency obligations and legal professional privilege creates a specific tension that needs to be resolved before any law firm can say its AI compliance framework is complete.</p><h2>The Core Tension</h2><p>Article 50 requires disclosure of AI use to clients and the maintenance of auditable records of that disclosure. Legal professional privilege protects certain communications between solicitors and clients from disclosure to third parties, including regulators. The question is what happens when the Article 50 compliance record itself contains information that might be subject to privilege, or when the regulator's demand for Article 50 records conflicts with the firm's privilege obligations to a client.</p><p>This is not a theoretical question. It is one that will arise in practice when EU AI Act enforcement begins.</p><h2>How I Think About This</h2><p>My view, and I want to be clear that this is a technical forensic assessment not legal advice, is that Article 50 compliance records can be structured in a way that separates the disclosure mechanism from the privileged content. The record does not need to contain the substance of the advice. It needs to contain evidence that disclosure happened, when it happened, and that the AI use was documented. That is a process record, not a privileged communication.</p><p>The key is building the compliance framework with this distinction built in from the start. A compliance record that inadvertently contains privileged content creates a problem. A compliance record designed to document the disclosure process without capturing the underlying advice does not.</p><h2>What This Means for Your Compliance Framework</h2><p>If your firm is building its Article 50 compliance framework without legal input on the privilege question, you may be creating records that are simultaneously non-compliant with Article 50 and potentially problematic for privilege. The Axiom Forensics Emergency Protocol builds the compliance framework with this distinction specifically addressed. It is one of the reasons our documentation is described as attorney-reviewable. It is designed to work within the privilege framework, not against it.</p>`},

  {id:"mid-market-law-firms-ai-act-exposure",tag:"LEGAL TECH",code:"WP-013",title:"Why Mid-Market Law Firms Face Proportionally Higher EU AI Act Exposure Than Magic Circle",excerpt:"Large firms have compliance departments, legal tech teams, and resources. Mid-market firms have the same obligation and a fraction of the infrastructure. Here is what that gap means in practice.",date:"2026-01-22",readTime:"6 min",body:`<p>I am going to say something that the compliance market rarely says clearly. The EU AI Act's compliance burden falls disproportionately on mid-market law firms, not on the large firms that dominate the legal tech conversation.</p><p>Magic Circle and large US firms have dedicated legal technology teams, compliance departments with AI specialists, vendor relationships with the major legal AI platforms, and the budget to build comprehensive governance frameworks. They are still not all compliant, but they have the infrastructure to get there.</p><p>A 40-partner firm in Manchester or Dublin using Harvey AI, Copilot, and Clio Duo has the same Article 14 and Article 50 obligations as Clifford Chance. It does not have the same infrastructure to meet them.</p><h2>The Specific Gaps I Find at Mid-Market Firms</h2><p>I run the same three forensic markers at every firm regardless of size. At mid-market firms, all three typically fail on the first assessment. FM1 fails because there is no systematic log linkage between AI outputs and human reviewer records. FM2 fails because oversight is attributed to practice groups or departments rather than named individuals. FM3 fails because there is no challenge protocol, no override mechanism, and human reviewers are approving AI outputs without any documented engagement with the substance.</p><p>These are not failures of intent. They are failures of infrastructure. The firm intended to be compliant. Nobody built the system that makes compliance demonstrable.</p><h2>The Cost of Getting This Wrong</h2><p>The penalty structure under Article 99 does not scale proportionately to firm size in a way that protects mid-market firms. The floor is €15 million or 3% of global annual turnover for certain violations. For a mid-market firm, that floor is potentially existential. The firms that think this regulation is aimed at large tech companies are misreading it. It is aimed at any deployer of high-risk AI. And a 40-partner firm using Harvey AI is a deployer of high-risk AI.</p><p>The Emergency Protocol was designed specifically for firms that need comprehensive compliance documentation without the overhead of a months-long consulting engagement. Forty eight hours. Court-ready documentation. A fixed fee. That is what mid-market compliance looks like.</p>`},

  {id:"underwriting-ai-annex-iii-2026",tag:"INSURANCE",code:"WP-014",title:"Your Underwriting AI Is Annex III High-Risk. Here Is What That Classification Actually Requires.",excerpt:"Most insurance firms know their underwriting AI is high-risk under Annex III. Very few understand what that classification requires them to document before August 2.",date:"2026-01-15",readTime:"8 min",body:`<p>I want to start with the classification itself, because I find that many insurance firms accept the Annex III high-risk designation for their underwriting AI without fully understanding what it triggers. Accepting the classification is step one. Understanding what the classification requires is where most firms stall.</p><h2>What Annex III Actually Says</h2><p>Annex III of the EU AI Act lists the specific categories of AI systems that are classified as high-risk. Section 5(b) covers AI systems used to evaluate the creditworthiness of natural persons or establish their credit score. Section 5(c) covers AI systems used in the context of life and health insurance for risk assessment and pricing. Both of these classifications cover the core underwriting AI systems used by most insurance firms.</p><p>The classification is not based on how good the AI is, how carefully it is supervised, or how long the firm has been using it. If the system does what those sections describe, it is high-risk. Full stop.</p><h2>The Documentation Pyramid</h2><p>High-risk classification triggers a documentation pyramid. At the base is technical documentation demonstrating how the system works, what data it uses, and how it was validated. Above that is the risk management documentation showing how the firm has assessed and mitigated the AI's risks. Above that is the human oversight documentation showing how Article 14 is being met. At the apex is the audit trail that connects all of this to the actual decisions the system has made.</p><p>When I run an Axiom Forensics assessment on an underwriting AI deployment, I am checking all four levels of this pyramid. What I almost always find is that the base level technical documentation exists in some form, but the audit trail at the apex is incomplete or absent. The human oversight layer, specifically the traceable connection between AI underwriting outputs and named human reviewers, is the most common critical finding.</p><h2>What a Regulator Will Ask For</h2><p>I find it useful to think about this from the regulator's perspective. An AI Act regulator arriving at your firm will ask for the same things I ask for in a forensic assessment. Show me the underwriting decisions your AI made in the last six months. Show me who reviewed each decision. Show me how that reviewer's involvement is documented. Show me what would have happened if the reviewer disagreed with the AI output.</p><p>If you cannot answer all four of those questions with documentary evidence, you have an Article 14 compliance gap. The Emergency Protocol produces the documentation that answers all four. In 48 hours.</p>`},

  {id:"pi-renewal-ai-compliance-insurance",tag:"INSURANCE",code:"WP-015",title:"Your PI Renewal Is Coming. Your AI Governance Documentation Is Not Ready. Here Is Why That Matters.",excerpt:"Professional indemnity insurers are asking new questions about AI at renewal. Firms that cannot answer them face coverage gaps, premium increases, or both.",date:"2026-02-10",readTime:"6 min",body:`<p>Professional indemnity renewal conversations have changed in the last twelve months. I have heard this from brokers, from compliance officers, and from the firms themselves. Questions that did not appear on renewal questionnaires eighteen months ago are now standard. What AI tools does the firm use? What governance framework is in place? What documentation can the firm produce to demonstrate compliance with applicable AI regulations?</p><p>Most firms are not ready to answer those questions well. And the consequences of answering them poorly at renewal are not abstract.</p><h2>What Insurers Are Actually Asking</h2><p>The questions vary by insurer and broker, but the cluster is consistent. AI tool inventory. Evidence of governance framework. Documentation of human oversight for AI-assisted decisions. Evidence of client disclosure for AI use in client work. Some insurers are also asking about the firm's EU AI Act compliance status specifically, particularly for firms with EU clients or operations.</p><p>A firm that can produce an Axiom Forensics audit report at renewal is answering all of those questions with a single document. The audit report contains the AI tool inventory, the governance assessment, the human oversight documentation, and the Article 14 and Article 50 compliance records. It is the answer to every question on the renewal questionnaire.</p><h2>The Coverage Gap Risk</h2><p>Here is what concerns me about firms that cannot produce this documentation at renewal. Insurers are beginning to add AI governance warranty clauses to PI policies. The clause requires the firm to warrant that its AI systems are governed in accordance with applicable regulation. If the firm cannot demonstrate that, and subsequently faces an AI Act enforcement action, the insurer may have grounds to decline coverage on the basis of the warranty breach.</p><p>This is not theoretical. It is the direction the market is moving. Firms that have their AI governance documentation in place before renewal are protected. Firms that do not are potentially holding a PI policy that will not respond when they need it most.</p><p>The Emergency Protocol produces the documentation before your renewal date. That is the practical objective. If your renewal is coming up and your AI governance documentation is not ready, this is the conversation to have now.</p>`},

  {id:"claims-ai-article14-oversight",tag:"INSURANCE",code:"WP-016",title:"Automated Claims Processing and Article 14: The Human Oversight Gap Most Carriers Have Not Fixed",excerpt:"Claims AI is making decisions at scale. The human oversight documentation required by Article 14 is rarely keeping pace. Here is what the gap looks like.",date:"2026-02-24",readTime:"7 min",body:`<p>Claims processing is one of the areas where AI has delivered the most obvious operational value to insurance carriers. Automated first notice of loss processing, AI-assisted coverage determination, algorithmic fraud detection, automated settlement recommendations. The efficiency gains are real and significant.</p><p>The Article 14 compliance gap is equally real and equally significant.</p><h2>The Scale Problem</h2><p>The challenge with claims AI is specifically one of scale. A carrier processing ten thousand claims per month through an AI system has ten thousand potential Article 14 compliance events per month. Each one requires a demonstrable human oversight record. Each one requires a named human reviewer. Each one requires evidence that the reviewer engaged with the output rather than just approving it.</p><p>Most carriers have humans in the claims process. Almost none have the systematic documentation that connects those humans to specific AI outputs in a way that creates an auditable Article 14 record at scale.</p><h2>What FM3 Reveals in Claims AI Audits</h2><p>When I run FM3, the Decision Reversibility marker, against a claims AI deployment, I am looking at the outcome distribution across the full audit period. What I find in most first assessments is a pattern that should concern every claims director. The override rate is effectively zero. Humans are reviewing AI recommendations and approving them at rates approaching one hundred percent. That is not oversight. That is passive monitoring. And the EU AI Act is explicit that passive monitoring does not satisfy Article 14.</p><p>A zero override rate is not evidence that the AI is always right. It is evidence that the oversight mechanism is not functioning as a genuine check on the AI. Regulators reading the same data will reach the same conclusion.</p><h2>Building a Compliant Claims AI Oversight Framework</h2><p>The solution is not to slow down claims processing or remove AI from the workflow. It is to build the oversight documentation layer that the AI workflow is currently missing. Named reviewers. Linked logs. A documented challenge protocol with a defined minimum override threshold. These are structural changes, not operational ones. They do not slow the claims process. They create the documentary evidence that the process is supervised by accountable humans.</p><p>That is what the Emergency Protocol builds. In 48 hours. For a claims AI deployment of any scale.</p>`},

  {id:"insurance-ai-audit-trail-regulator",tag:"INSURANCE",code:"WP-017",title:"What Would a Regulator Actually Find in Your AI Logs Today?",excerpt:"I have run this exercise at enough firms to know the answer is almost always uncomfortable. Here is what the audit trail usually reveals and what it should look like.",date:"2026-03-12",readTime:"7 min",body:`<p>I want to ask you a direct question. If an EU AI Act regulator arrived at your firm today, with a formal request for your AI decision logs and oversight records for the last six months, what would they find?</p><p>I have run this exercise enough times to know what the answer usually is. Not because firms are negligent. Because the documentation infrastructure was never built.</p><h2>What the Logs Usually Show</h2><p>The decision logs exist. Most AI systems generate output logs as a matter of course. The AI made a recommendation. The recommendation was timestamped. The outcome was recorded. That part of the audit trail is usually intact.</p><p>What is usually missing is everything after that. Who reviewed the recommendation. When the review happened. What the reviewer's authority was. Whether the reviewer could have overridden the recommendation and whether they ever did. The connection between the AI output and the human decision.</p><p>When I run FM1 against a new client's logs, I am running a single query. I am joining the decision log to the review log on a shared identifier. In the majority of first audits, that join produces no results. The decision logs and the review logs exist independently, with no documented connection between them. From a regulatory perspective, that is the same as having no human oversight at all.</p><h2>The Three Things That Are Always Missing</h2><p>Across every insurance firm I have audited, the same three gaps appear with remarkable consistency. First, the reviewer identity. The review log shows a review happened, but the reviewer is a shared team account, not a named individual. Second, the linkage. The decision log and the review log are not connected by a shared identifier. They exist in parallel, not in sequence. Third, the challenge record. There is no documentation of the reviewer engaging substantively with the AI output. Approvals are recorded. Challenges are not.</p><p>Each of these is independently a critical finding under the Axiom Oversight Metric. Together they represent a firm that has humans involved in its AI process but cannot demonstrate human oversight in the way the regulation requires.</p><h2>What the Logs Should Show</h2><p>A compliant audit trail shows a decision log entry connected by a unique identifier to a review log entry attributed to a named individual, with a timestamp showing the review happened before any consequential action was taken, and with a field documenting the reviewer's substantive engagement, including any challenge or override. That is the documentary chain that satisfies Article 14. That is what the Emergency Protocol builds.</p>`},

  {id:"creditlogic-irish-fintech-audit",tag:"FINTECH",code:"WP-018",title:"What the Meridian Credit Solutions Audit Revealed About Irish Fintech AI Compliance",excerpt:"The Meridian engagement was the first full Axiom Forensics audit in the Irish market. What we found reflects a pattern across Irish fintech. Here is the detailed picture.",date:"2026-02-05",readTime:"9 min",body:`<p>I want to talk about the Meridian Credit Solutions engagement in some detail, because I think it illustrates something important about where Irish fintech sits on AI compliance right now. This is not a criticism of Meridian specifically. The finding profile we documented at Meridian reflects what I expect to find at the majority of Irish fintech firms using AI for credit decisions. Meridian simply went first.</p><h2>The Engagement Context</h2><p>Meridian Credit Solutions is a Dublin-based credit firm using CreditLogic version 3.2 for automated credit decision making. The system processes approximately four thousand two hundred decisions per day, classifying applicants for credit products. Under Annex III Section 5(b) of the EU AI Act, CreditLogic v3.2 is a high-risk AI system. Meridian engaged Axiom Forensics for a full forensic audit under reference AXM-2026-IRL-FT-001.</p><h2>The Three Critical Findings</h2><p>The audit produced three critical findings across the five AOM pillars, resulting in an overall score of 41 out of 100. Material Risk band. Certificate of Compliance withheld.</p><p>Finding F-001 was a Log Integrity Failure. When I ran FM1, joining the decision log to the review log on decision_id, every one of the four thousand two hundred daily records showed reviewer_id as NULL. The decision logs were intact and detailed. The review logs did not exist in a linked form. There was no documentary connection between a single CreditLogic output and a single human reviewer. From a regulatory perspective, this means four thousand two hundred credit decisions per day are being made without documented human oversight.</p><p>Finding F-002 was an Actor Attribution Failure. When I ran FM2, grouping the review log by reviewer_id, a single result returned. One shared service account, compliance_review at meridian dot ie, was attributed as the reviewer for every review in the audit period. There was no named individual accountable for any oversight decision. No person could be held personally responsible for any review.</p><p>Finding F-003 was a Decision Reversibility Failure. FM3 showed a one hundred percent approval rate across the full audit period. Zero declined. Zero overridden. Four thousand two hundred AI recommendations, all approved without exception. This is passive monitoring. Under the EU AI Act, passive monitoring does not constitute human oversight.</p><h2>What This Means for Irish Fintech Generally</h2><p>I am not going to pretend the Meridian findings are unusual. They are the norm. The Irish fintech sector has adopted AI credit decisioning at significant scale, and the compliance infrastructure has not kept pace with the technical deployment. The tools are sophisticated. The oversight documentation is not.</p><p>The Central Bank of Ireland is watching this space. Enforcement actions under the EU AI Act carry consequences that extend beyond fines. They affect licensing, they affect investor confidence, and they affect the commercial relationships that Irish fintech firms depend on. The window to get ahead of this is measured in weeks, not months.</p><p>The Meridian remediation pack is available as a reference document for Irish fintech firms beginning their own compliance journey. The simulation engagement is the fastest way to understand your own position before committing to a full audit. That is where I recommend starting.</p>`},

  {id:"central-bank-ireland-ai-compliance",tag:"FINTECH",code:"WP-019",title:"The Central Bank of Ireland and EU AI Act: What Irish Firms Need to Know Before August 2",excerpt:"The Central Bank has been clear about its expectations for AI governance in regulated entities. What it requires before August 2 is more specific than most Irish firms have prepared for.",date:"2026-02-18",readTime:"7 min",body:`<p>The Central Bank of Ireland sits at an interesting intersection in the AI compliance landscape. As the national competent authority for financial services regulation in Ireland, it has its own expectations for AI governance in regulated entities. As an EU institution in practical terms, it will also be involved in the enforcement architecture of the EU AI Act as it applies to Irish firms. Understanding both dimensions is important for any Irish regulated entity using AI in its core processes.</p><h2>What the Central Bank Has Said on AI</h2><p>The Central Bank has published guidance and consultation papers on AI in financial services that are worth reading carefully alongside the EU AI Act requirements. Its consistent message is that regulated entities must maintain human accountability for AI-assisted decisions, particularly in credit, underwriting, and compliance functions. The Bank has been explicit that AI does not transfer regulatory accountability. The regulated entity remains responsible for every consequential decision, regardless of how much AI was involved in generating that decision.</p><p>This aligns directly with Article 14 of the EU AI Act. But the Central Bank's framing adds something important. It connects AI accountability to the broader accountability framework that regulated entities already operate under. This means non-compliance with Article 14 is not just an AI Act issue for Irish regulated entities. It potentially creates a regulatory accountability gap that the Central Bank can act on independently of any EU AI Act enforcement action.</p><h2>The Dual Regulator Risk</h2><p>Irish fintech and financial services firms face a dual regulator risk that firms in some other EU jurisdictions do not. The Central Bank can act on AI governance failures under its existing supervisory powers. The EU AI Act enforcement machinery can act on the same failures independently. These are not necessarily sequential. They can happen simultaneously, with compounding effect on the firm's regulatory standing.</p><p>This dual risk profile is one of the reasons I recommend Irish regulated entities treat August 2 as a hard deadline rather than a planning date. Getting ahead of both regulators simultaneously requires moving now. The Axiom Forensics Meridian Forensic Audit product was designed specifically for the Irish regulated market, with documentation structured to satisfy both the EU AI Act requirements and the Central Bank's accountability expectations.</p>`},

  {id:"article-99-exposure-calculator",tag:"FINTECH",code:"WP-020",title:"How to Estimate Your EU AI Act Article 99 Penalty Exposure Right Now",excerpt:"The penalty structure under Article 99 is well-known. What most firms have not done is applied it to their specific situation. Here is how to think about your actual exposure number.",date:"2026-03-01",readTime:"6 min",body:`<p>Everyone in the compliance market knows the headline number. Thirty five million euros or seven percent of global annual turnover, whichever is higher. But I find that this number functions as an abstraction for most firms rather than a concrete risk figure. Nobody sits down and calculates what it actually means for them. I want to walk through how to do that, because the exercise tends to concentrate minds in a way that the abstract headline does not.</p><h2>The Three Violation Tiers</h2><p>Article 99 has three penalty tiers, and which one applies depends on the nature of the violation. The highest tier, up to thirty five million euros or seven percent of turnover, applies to prohibited AI practices and serious violations of high-risk system requirements. The middle tier, up to fifteen million euros or three percent of turnover, applies to violations of obligations for high-risk systems including Article 14 human oversight failures and Article 50 transparency failures. The lowest tier, up to seven point five million euros or one percent of turnover, applies to providing incorrect information to authorities.</p><p>For most law firms and insurance carriers, the relevant tier is the middle one. Fifteen million euros or three percent of global annual turnover. That is the exposure calculation to run.</p><h2>Running the Calculation</h2><p>Take your firm's global annual turnover. Calculate three percent of that figure. Compare it to fifteen million euros. The higher number is your maximum exposure under the middle penalty tier. For a firm with annual turnover of one hundred million euros, three percent is three million euros, which is lower than fifteen million. Your maximum exposure is fifteen million. For a firm with turnover of six hundred million euros, three percent is eighteen million, which is higher than fifteen million. Your maximum exposure is eighteen million.</p><p>Now add the retroactive dimension. Liability accrues from the date of deployment. If your firm has been running an Article 14 non-compliant AI system since 2024, regulators can calculate the penalty from that date. The exposure is not just for future non-compliance. It is for every day of past non-compliance since deployment.</p><h2>What This Number Should Tell You</h2><p>I am not raising this to create alarm for its own sake. I am raising it because the commercial decision to invest in compliance documentation becomes very clear when you put your actual exposure number next to the cost of the Emergency Protocol. One is a fixed, known, manageable cost. The other is an uncertain but potentially very large liability. The calculation is not complicated. The Emergency Protocol is the right commercial decision for any firm whose exposure number is significantly larger than the engagement fee. That is almost every firm I work with.</p>`},

  {id:"eu-ai-act-dublin-fintech-exposure",tag:"FINTECH",code:"WP-021",title:"Why Dublin Fintech Firms Are Disproportionately Exposed to EU AI Act Enforcement",excerpt:"Dublin's position as an EU financial hub creates specific AI Act obligations that firms in other jurisdictions do not face in the same way. Here is the picture.",date:"2026-03-20",readTime:"6 min",body:`<p>Dublin holds a unique position in the EU financial services landscape. As the primary English-speaking EU financial hub post-Brexit, it hosts a significant concentration of fintech firms, financial services operations, and regulated entities that specifically chose Dublin for its EU regulatory status. That same EU regulatory status creates a specific EU AI Act exposure that firms in Dublin need to understand clearly.</p><h2>The Hub Effect</h2><p>Many firms based in Dublin are there precisely because of EU market access. Their business model depends on being able to operate across the EU single market without regulatory friction. That is their competitive advantage. It is also, under the EU AI Act, a compliance obligation that extends across every EU jurisdiction in which they operate.</p><p>A Dublin fintech firm with customers in Germany, France, and Ireland is not just subject to Irish implementation of the EU AI Act. It is subject to the Act as it applies in all three jurisdictions. Its Article 14 and Article 50 obligations extend to every EU customer interaction. Its penalty exposure is calculated on global annual turnover, not just Irish turnover.</p><h2>The Central Bank Multiplier</h2><p>I wrote about this in the Central Bank article, but it is worth repeating in the Dublin context. Dublin fintech firms face a Central Bank of Ireland supervisory layer on top of the EU AI Act enforcement layer. These are not the same thing. They can operate simultaneously. A compliance failure that attracts EU AI Act enforcement can also attract Central Bank supervisory attention under the Bank's existing powers. For a regulated entity, the combination is more serious than either alone.</p><h2>The Window Is Specific</h2><p>The Meridian engagement demonstrated something important about the Irish market. The firms here have deployed sophisticated AI infrastructure. The compliance documentation layer has not kept pace. The gap between what the technology does and what the documentation proves is significant, and August 2 is the date at which that gap becomes a regulatory liability. Dublin fintech firms that act now are protecting their EU market access. That is the commercial framing that matters most for this market.</p>`},

  {id:"ai-hiring-systems-annex-iii-article14",tag:"HR TECH",code:"WP-022",title:"Your AI Hiring System Is High-Risk Under Annex III. Here Is What Your HR Team Does Not Know.",excerpt:"AI recruitment tools are explicitly classified as high-risk under Annex III. The Article 14 obligations they trigger are not being met at most organisations.",date:"2025-11-25",readTime:"6 min",body:`<p>I want to talk about something that tends to get less attention than legal AI or financial services AI in the compliance conversation, but that creates very specific exposure for a large number of organisations. AI systems used in recruitment and HR decision-making are explicitly classified as high-risk under Annex III of the EU AI Act. And the Article 14 compliance gap I find in HR AI deployments is, if anything, more severe than in financial services.</p><h2>What Annex III Says About HR AI</h2><p>Annex III Section 4 covers AI systems used in employment and workers management. It specifically includes AI used for recruitment or selection of natural persons, and AI used to make or inform decisions affecting terms and conditions of employment. If your organisation uses an AI system to screen CVs, rank candidates, schedule interviews, assess interview performance, or inform promotion or redundancy decisions, that system is Annex III high-risk.</p><p>This applies to standalone recruitment AI and to AI features embedded in HR platforms. If your ATS uses AI scoring, it is high-risk. If your video interview platform uses AI analysis, it is high-risk. The classification does not depend on how the AI is marketed. It depends on what it does.</p><h2>The Article 14 Gap in HR AI</h2><p>When I run FM1 against an HR AI deployment, I am looking for the documented connection between the AI's candidate assessment and the human hiring decision. What I find in almost every engagement is that the human made the hiring decision, the AI produced a score or ranking, and there is no documentary record connecting the two in a way that demonstrates the human exercised genuine oversight rather than simply acting on the AI output.</p><p>FM2 reveals a related problem. The oversight records that do exist are typically attributed to the HR department or the hiring team rather than to a named individual with documented authority. FM3 shows the predictable result: the AI recommendation is almost never overridden, which is evidence of passive monitoring rather than active oversight.</p><p>The employment law dimension of this is particularly serious. An unsuccessful candidate who challenges an AI-influenced hiring decision can request to see the oversight documentation. If it does not exist, the organisation has an EU AI Act compliance failure and potentially an employment law exposure simultaneously. The Emergency Protocol builds the documentation that protects against both.</p>`},

  {id:"medtech-ai-compliance-ireland",tag:"MED TECH",code:"WP-023",title:"MedTech AI Compliance in Ireland: The Documentation Obligation Nobody Is Discussing",excerpt:"Irish MedTech firms using AI in clinical decision support or patient pathway management face high-risk classification. Most have not started the compliance documentation that August 2 requires.",date:"2026-01-28",readTime:"7 min",body:`<p>The MedTech sector in Ireland has embraced AI more rapidly than almost any other industry. AI-assisted diagnostic support, clinical pathway optimisation, patient risk stratification, automated monitoring systems. The clinical benefits are real and significant. The EU AI Act compliance picture is, for most Irish MedTech firms, significantly behind where it needs to be.</p><h2>The Classification Picture for MedTech AI</h2><p>MedTech AI sits at a complex intersection of regulatory frameworks. AI systems used as safety components in medical devices are classified as high-risk under Annex III of the EU AI Act. They are also subject to the Medical Devices Regulation and the In Vitro Diagnostic Regulation, which have their own conformity assessment requirements. The EU AI Act does not replace those existing frameworks. It adds to them.</p><p>For an Irish MedTech firm using AI in a clinical decision support context, this means the Article 14 human oversight requirements of the EU AI Act apply alongside the existing MDR requirements. The compliance documentation burden is layered, not single.</p><h2>What I Find in MedTech AI Audits</h2><p>The pattern in MedTech AI audits is distinctive from financial services audits in one important respect. The clinical documentation culture in healthcare tends to produce better base-level records than financial services. Clinical events are documented. Patient interactions are recorded. What is often missing is the specific documentary connection that Article 14 requires between the AI system output and the human clinical decision.</p><p>The AI produced a risk stratification score. A clinician reviewed it. The clinician made a clinical decision. The Article 14 compliance question is whether there is a documented record connecting that AI score to that clinician's review, with the clinician identified by name, with evidence that the clinician engaged substantively with the score rather than simply accepting it. In most MedTech deployments I review, that specific record does not exist.</p><h2>The August 2 Pressure for MedTech</h2><p>Irish MedTech firms face the August 2 deadline alongside the ongoing MDR compliance obligations and in the context of a sector that is under significant scrutiny from both the Health Products Regulatory Authority and European regulators. Building the Article 14 compliance documentation now, before the enforcement date, is both a regulatory obligation and a commercial prudence for any Irish MedTech firm that wants to protect its market position in the EU. The Emergency Protocol is deployable for MedTech AI systems with the same 48-hour delivery commitment that applies across all Axiom Forensics engagements.</p>`},

  {id:"passive-monitoring-article14-violation",tag:"METHODOLOGY",code:"WP-024",title:"What Passive Monitoring Actually Looks Like — And Why Regulators Treat It as No Oversight",excerpt:"A 100% approval rate is not evidence your AI is accurate. It is evidence your oversight is not working. Here is how regulators read that data.",date:"2026-03-15",readTime:"7 min",body:`<p>I want to explain something that comes up in almost every audit I run, and that I think is genuinely misunderstood by most compliance teams. The concept of passive monitoring, and why the EU AI Act treats it not as imperfect oversight but as no oversight at all.</p><h2>What Passive Monitoring Looks Like</h2><p>Passive monitoring looks, on the surface, like proper oversight. There is a human in the process. The human is reviewing AI outputs. The AI makes a recommendation. The human approves it. This happens systematically, at scale, with records showing that every AI output was reviewed before action was taken.</p><p>The problem is in the approval rate. When I run FM3 against a set of AI decision logs and find a one hundred percent approval rate across thousands of decisions over months of operation, I am not looking at evidence that the AI is always right. I am looking at evidence that humans are not genuinely engaging with the AI outputs. They are processing them. They are not reviewing them.</p><h2>Why the Distinction Matters</h2><p>Article 14 of the EU AI Act requires human oversight that is meaningful. The word meaningful is doing significant work in the regulatory text. Meaningful oversight requires that the human reviewer understands what the AI is recommending, has the authority and capacity to challenge it, and exercises that authority when the recommendation warrants challenge. A reviewer who approves every output without exception over months of operation is not exercising meaningful oversight. They are a rubber stamp.</p><p>Regulators reading FM3 data will reach the same conclusion I do. A zero override rate is not a compliance feature. It is a compliance failure indicator. It suggests either that the reviewers lack the authority or confidence to challenge the AI, or that the review process is not designed to facilitate genuine challenge, or both. Any of those explanations represents an Article 14 failure.</p><h2>What Genuine Oversight Looks Like in the Logs</h2><p>Genuine oversight shows a non-trivial override rate. Not necessarily high. In a well-calibrated AI system with experienced reviewers, a two to five percent override rate is credible. Zero is not credible. One hundred percent is not credible in the other direction. What regulators and I are looking for is evidence that the human review process is functioning as a genuine check on the AI, with documented instances of challenge, override, and escalation that demonstrate the oversight mechanism is real and not ceremonial.</p><p>Building that evidence base is what the Emergency Protocol does. It is not about slowing down the AI process. It is about creating the documentary record that proves the human oversight is genuine. That distinction is what separates compliant oversight from passive monitoring in a regulatory examination.</p>`},

  {id:"three-forensic-markers-axiom-methodology",tag:"METHODOLOGY",code:"WP-025",title:"The Three Forensic Markers: How Axiom Forensics Audits an AI System in the First 60 Minutes",excerpt:"FM1, FM2, and FM3 are run within 60 minutes of receiving client log data. Here is exactly what each one tests, why it matters, and what finding it reveals.",date:"2026-03-22",readTime:"8 min",body:`<p>I want to be transparent about how we work. One of the things that I think distinguishes Axiom Forensics from the broader AI governance consulting market is that our methodology is forensic rather than advisory. We are not producing a gap analysis based on interviews and policy reviews. We are running queries against live log data and producing findings based on what the data actually shows. The three forensic markers are the core of that methodology, and I want to explain each one in detail.</p><h2>FM1: Intervention Delta</h2><p>FM1 tests whether AI decision logs are linked to human review records by a shared identifier. The query is straightforward. We join the decision log table to the review log table on a shared decision identifier. If the join produces results, the linkage exists. If it does not, the logs are unlinked.</p><p>What an unlinked result means in practice is that the AI system is producing outputs and the human review process is operating in parallel, with no documentary connection between them. From a regulatory perspective, unlinked logs are equivalent to having no human oversight record. The AI made decisions. Humans may or may not have reviewed them. There is no documentary evidence either way.</p><p>FM1 is the most common critical finding in first audits. It fails more often than FM2 or FM3, because most AI deployments were built with strong output logging and weak review logging, and the connection between the two was never systematically established.</p><h2>FM2: Actor Attribution</h2><p>FM2 tests whether human reviewers are named individuals with documented authority, or whether the review function has been attributed to shared accounts, team accounts, or role identifiers. We group the review log by reviewer ID and examine the results.</p><p>A shared account finding, where one account is attributed to all reviews, means that personal accountability for oversight decisions cannot be established. Article 14 requires that the humans exercising oversight are identifiable and accountable. A shared account satisfies neither requirement. Nobody can be asked to account for a review decision made under a shared account. Nobody can be held responsible for failing to challenge an AI output when the reviewer identity is a team email address.</p><p>FM2 failures are particularly serious in regulated sectors where personal accountability is a core regulatory expectation, specifically financial services, insurance, and legal practice.</p><h2>FM3: Decision Reversibility</h2><p>FM3 tests whether the human oversight is active or passive. We run an outcome distribution query across the full audit period, examining the rate at which human reviewers challenged or overrode AI recommendations. A non-trivial override rate is evidence of active oversight. A zero or near-zero override rate is evidence of passive monitoring.</p><p>The FM3 finding is often the one that surprises clients most. Firms are aware that their AI has a low override rate. They tend to interpret this as evidence that the AI is performing well. That may be true. But from a compliance perspective, it does not matter whether the AI is accurate. What matters is whether the human oversight mechanism is functioning as a genuine check. An override rate of zero is not consistent with genuine oversight, regardless of the AI's accuracy.</p><h2>Why These Three Markers First</h2><p>I run FM1, FM2, and FM3 within sixty minutes of receiving client log data because they are the three findings that most directly determine whether Article 14 compliance is achievable from the current state of the data. If all three pass, the compliance framework is substantially in place and the remaining work is documentation and formalisation. If any one fails, it is a critical finding that requires remediation before a Certificate of Compliance can be issued. Knowing the FM status within the first hour shapes everything that follows in the audit.</p>`},

  {id:"law-firm-ai-governance-policy-not-enough",tag:"LEGAL TECH",code:"WP-026",title:"Your Law Firm Has an AI Policy. That Is Not the Same as AI Compliance.",excerpt:"Most law firms have drafted an AI usage policy in the last twelve months. Almost none have built the documentary framework the policy describes. Here is the gap.",date:"2026-01-05",readTime:"6 min",body:`<p>In the last eighteen months, almost every law firm of any size has produced an AI usage policy. Some are detailed. Some are brief. Most include the right language about responsible AI use, human oversight, client disclosure, and compliance with applicable regulation. And almost none of them have produced the documentary evidence that the policy describes.</p><p>That is the gap I want to talk about. The gap between the policy and the practice. Between saying you have human oversight and having a documentary record that proves it.</p><h2>What a Policy Does and Does Not Do</h2><p>A policy is a statement of intent. It tells your partners, associates, and staff what the firm's position is on AI use. It creates an internal governance reference point. It demonstrates to clients and regulators that the firm has thought about the issue. These are valuable things. They are not compliance.</p><p>Compliance under the EU AI Act requires documentary evidence that the policy is being followed, at the level of individual decisions, in a form that a regulator can audit. The policy says reviewers must document their oversight of AI outputs. Compliance means there are records showing that reviewers documented their oversight of specific AI outputs on specific matters on specific dates. One is a commitment. The other is evidence.</p><h2>The Three Things a Policy Cannot Create</h2><p>A policy cannot create a linked log connecting AI outputs to named human reviewers. A policy cannot create an audit trail of individual oversight decisions with timestamps and reviewer identities. And a policy cannot create a record of genuine engagement with AI outputs as distinct from passive approval.</p><p>All three of those things require infrastructure. They require systems that capture the right data at the right time in the right format. Building that infrastructure is what the Emergency Protocol does. The policy is the starting point. The documentary framework is what makes the policy real.</p><h2>The Conversation I Have With Most Law Firms</h2><p>The conversation I have with most law firms starts the same way. The managing partner or compliance officer tells me the firm has an AI policy. I ask to see the oversight records for the last three months. There are no records in the form Article 14 requires. The policy exists. The compliance documentation does not. That is the gap the Emergency Protocol closes. In 48 hours. Starting with your existing AI tools and existing workflows.</p>`},

  {id:"magic-circle-vs-mid-market-ai-act",tag:"LEGAL TECH",code:"WP-027",title:"The Law Firm AI Act Gap: Why Smaller Firms Are More Exposed Than They Think",excerpt:"Large firms have compliance infrastructure. Smaller firms have the same obligation. Here is why that asymmetry creates disproportionate risk for mid-market and regional practices.",date:"2025-12-28",readTime:"5 min",body:`<p>There is a narrative in the legal AI compliance market that the EU AI Act is primarily a concern for large firms with significant AI deployments and complex governance structures. I want to challenge that narrative directly, because I think it is creating a false sense of security at exactly the firms that need to be moving fastest.</p><h2>The Obligation Is Symmetric. The Infrastructure Is Not.</h2><p>Article 14 applies equally to a forty partner regional firm and to a thousand partner global practice. The obligation to demonstrate human oversight of consequential AI decisions does not scale with firm size. The fine structure under Article 99 has a floor that is proportionately more significant for a smaller firm. Fifteen million euros is a larger fraction of a regional firm's annual turnover than it is for a Magic Circle practice.</p><p>What is not symmetric is the compliance infrastructure. Large firms have legal technology teams, risk and compliance departments, and the budget to commission comprehensive governance frameworks from Big 4 consultancies. Regional and mid-market firms typically have a managing partner who is also thinking about business development, a compliance officer who is also handling GDPR, and a budget that does not stretch to a six-figure consulting engagement.</p><h2>Why This Creates a Specific Risk</h2><p>The risk for smaller firms is not that they are using AI irresponsibly. Most of the firms I work with are using AI carefully and thoughtfully. The risk is that they have deployed AI tools, often Harvey, Copilot, or Clio Duo, without building the documentation infrastructure that Article 14 requires, because nobody told them the documentation infrastructure was a separate thing from the tool deployment.</p><p>The tool vendor provides the tool. The compliance documentation is the firm's responsibility. That separation is not always clear when you are a managing partner approving a Harvey AI subscription and trusting that the vendor has handled the regulatory considerations. They have handled their regulatory considerations. Yours are still outstanding.</p><p>The Emergency Protocol was built for exactly this firm. A fixed fee. A 48-hour delivery. Court-ready documentation that does not require a months-long engagement or an enterprise budget. That is what proportionate compliance looks like for a mid-market or regional firm that needs to be ready by August 2.</p>`}
];

// Render intel grid
const PREVIEW_COUNT = 6;
let showingAll = false;

function renderArticles() {
  const grid = document.getElementById("intel-grid");
  if (!grid) return;
  grid.innerHTML = '';
  const toShow = showingAll ? articles : articles.slice(0, PREVIEW_COUNT);
  toShow.forEach(a => {
    const card = document.createElement("div");
    card.className = "intel-card";
    card.style.cursor = "pointer";
    card.innerHTML = `<div class="card-meta"><span style="color:var(--dim)">${a.code}</span><span class="card-tag">${a.tag}</span></div><div class="card-title">${a.title}</div><div class="card-excerpt">${a.excerpt}</div><div class="card-read"><span>${a.readTime} read</span><span>—</span><span>${a.date}</span></div>`;
    card.addEventListener('click', function(e) {
      e.preventDefault();
      e.stopPropagation();
      openArticle(a);
    });
    card.addEventListener('touchend', function(e) {
      e.preventDefault();
      e.stopPropagation();
      openArticle(a);
    });
    grid.appendChild(card);
  });
  const btn = document.getElementById('view-all-btn');
  if (btn) btn.textContent = showingAll ? '← Show Less' : `View All ${articles.length} Articles →`;
}

// Page routing
function showPage(name) {
  document.querySelectorAll(".page").forEach(p => p.classList.remove("active"));
  var pg = document.getElementById("page-"+name);
  if (!pg) return;
  pg.classList.add("active");
  window.scrollTo(0,0);
  if (name === "portal") {
    var shell = document.getElementById("portal-login-shell");
    var dash = document.getElementById("portal-dashboard");
    if (shell) shell.style.display = "flex";
    if (dash) dash.style.display = "none";
  }
}

// Article
function openArticle(a) {
  const liLink = document.getElementById("li-share-link");
  if(liLink) liLink.href = "https://www.linkedin.com/sharing/share-offsite/?url=" + encodeURIComponent("https://axiomforensics.cloud") + "&title=" + encodeURIComponent(a.title);
  document.getElementById("article-meta").innerHTML = `<span class="article-tag-label">${a.tag}</span><span>${a.code}</span><span>${a.date}</span><span>${a.readTime} read</span>`;
  document.getElementById("article-title").textContent = a.title;
  document.getElementById("article-body").innerHTML = a.body;
  showPage("article");
}


// Cookie consent
function acceptCookies() {
  localStorage.setItem('axiom_cookies', 'accepted');
  document.getElementById('cookie-bar').classList.add('hidden');
}
function declineCookies() {
  localStorage.setItem('axiom_cookies', 'declined');
  document.getElementById('cookie-bar').classList.add('hidden');
  // Disable GA if declined
  window['ga-disable-G-5YY0VS4KPQ'] = true;
}
(function() {
  const consent = localStorage.getItem('axiom_cookies');
  if (consent) {
    document.getElementById('cookie-bar').classList.add('hidden');
    if (consent === 'declined') window['ga-disable-G-5YY0VS4KPQ'] = true;
  }
})();

// Countdown
function updateCountdown() {
  const end = new Date("2026-08-02T00:00:00");
  const now = new Date();
  const diff = Math.max(0, end - now);
  const d = Math.floor(diff/86400000);
  const h = Math.floor(diff%86400000/3600000);
  const m = Math.floor(diff%3600000/60000);
  const s = Math.floor(diff%60000/1000);
  document.getElementById("cd-days").textContent = String(d).padStart(3,"0");
  document.getElementById("cd-hours").textContent = String(h).padStart(2,"0");
  document.getElementById("cd-mins").textContent = String(m).padStart(2,"0");
  document.getElementById("cd-secs").textContent = String(s).padStart(2,"0");
  const daysEl = document.getElementById("dash-days");
  if(daysEl) daysEl.textContent = d;
}
setInterval(updateCountdown,1000);
updateCountdown();

// Notification
function notify(msg) {
  const n = document.getElementById("notif");
  n.textContent = msg;
  n.classList.add("show");
  setTimeout(() => n.classList.remove("show"), 4000);
}

