// Brief email capture — sends lead via Formspree
function handleBriefCapture() {
  const email = document.getElementById("brief-email").value.trim();
  if (!email || !email.includes("@")) { notify("Please enter a valid firm email address."); return; }
  const name = document.getElementById("brief-name") ? document.getElementById("brief-name").value.trim() : "Brief Request";
  fetch("https://formspree.io/f/mlgpvejw", {
    method: "POST",
    headers: {"Content-Type": "application/json"},
    body: JSON.stringify({
      name: name || "Brief Request",
      email: email,
      message: "Requested the AI Act Compliance Protocol Brief from axiomforensics.cloud",
      _replyto: email
    })
  }).then(() => {
    document.getElementById("brief-email").value = "";
    showPage('thankyou');
  }).catch(() => {
    notify("Error. Please email audit@axiomforensics.cloud to request the brief directly.");
  });
}

// Intake form multi-step
let currentStep = 1;
const totalSteps = 3;

function nextStep() {
  const current = document.getElementById('form-step-' + currentStep);
  if (currentStep < totalSteps) {
    if (current) current.style.display = 'none';
    currentStep++;
    const next = document.getElementById('form-step-' + currentStep);
    if (next) next.style.display = 'block';
    updateStepIndicator();
  }
}

function prevStep() {
  const current = document.getElementById('form-step-' + currentStep);
  if (currentStep > 1) {
    if (current) current.style.display = 'none';
    currentStep--;
    const prev = document.getElementById('form-step-' + currentStep);
    if (prev) prev.style.display = 'block';
    updateStepIndicator();
  }
}

function updateStepIndicator() {
  const indicators = document.querySelectorAll('.step-dot');
  indicators.forEach((dot, i) => {
    dot.classList.toggle('active', i < currentStep);
  });
}

function submitForm() {
  const name = document.getElementById('f-name') ? document.getElementById('f-name').value.trim() : '';
  const firm = document.getElementById('f-firm') ? document.getElementById('f-firm').value.trim() : '';
  const email = document.getElementById('f-email') ? document.getElementById('f-email').value.trim() : '';
  const phone = document.getElementById('f-phone') ? document.getElementById('f-phone').value.trim() : '';
  const size = document.getElementById('f-size') ? document.getElementById('f-size').value : '';
  const jurisdiction = document.getElementById('f-jurisdiction') ? document.getElementById('f-jurisdiction').value : '';
  const cloud = document.getElementById('f-cloud') ? document.getElementById('f-cloud').value : '';
  const urgency = document.getElementById('f-urgency') ? document.getElementById('f-urgency').value : '';
  const notes = document.getElementById('f-notes') ? document.getElementById('f-notes').value.trim() : '';
  const tools = Array.from(document.querySelectorAll('.ai-tool:checked')).map(el => el.value).join(', ');
  if (!email || !email.includes('@')) { notify('Please enter a valid email address.'); return; }
  if (!firm) { notify('Please enter your firm name.'); return; }
  fetch('https://formspree.io/f/mlgpvejw', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ name, firm_name: firm, email, phone, firm_size: size, jurisdiction, cloud, ai_tools: tools, urgency, notes, _replyto: email, message: `New assessment request from ${firm}. Urgency: ${urgency}. Tools: ${tools}. Notes: ${notes}` })
  }).then(() => {
    currentStep = 1;
    document.querySelectorAll('.form-step').forEach((s, i) => { s.style.display = i === 0 ? 'block' : 'none'; });
    showPage('thankyou');
  }).catch(() => { notify('Submission error. Please email audit@axiomforensics.cloud directly.'); });
}

document.addEventListener('DOMContentLoaded', function() {
  const steps = document.querySelectorAll('.form-step');
  steps.forEach((s, i) => { s.style.display = i === 0 ? 'block' : 'none'; });
  renderArticles();
});